window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2005>1","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Correct 0.04945 to two significant figures.","images":[],"options":{"A":"0.040","B":"0.049","C":"0.050","D":"0.49"},"answer":"B","explanation":"To correct 0.04945 to two significant figures, we look at the third digit (9) after the decimal point. Since it's less than 5, we keep the first two digits and drop the rest.    Therefore, 0.04945 rounded to two significant figures is 0.049.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>2","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:5&radic;3&nbsp;-3&radic;2&nbsp;","images":[],"options":{"A":"16(5&radic;3&nbsp;-3&radic;2&nbsp;)","B":"16(15&radic;3&nbsp;-6&radic;2&nbsp;)","C":"16(3&radic;2&nbsp;-&radic;3&nbsp;)","D":"16(10&radic;3&nbsp;-9&radic;2&nbsp;)"},"answer":"D","explanation":"5&radic;2&nbsp; - 3&radic;3&nbsp;&radic;6&nbsp;  Note: &radic;3&nbsp; \u00d7 &radic;2&nbsp; = &radic;6&nbsp;  Rationalise the denominator  5&radic;2&nbsp; - 3&radic;3&nbsp;&radic;6&nbsp;\u00d7&radic;6&nbsp;&radic;6&nbsp;  5&radic;12&nbsp; - 3&radic;18&nbsp;6=5&radic;4 \u00d7 3&nbsp; - 3&radic;9 \u00d7 2&nbsp;6  5 \u00d7 2&radic;3&nbsp; - 3 \u00d7 3&radic;3&nbsp;6\u21d210&radic;3&nbsp; - 9&radic;2&nbsp;6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>3","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Evaluate, correct to the nearest whole number:  712-(212+3)\u00f7332","images":[],"options":{"A":"33","B":"8","C":"7","D":"0"},"answer":"C","explanation":"712-(212+3)\u00f7332  Using BODMAS Rule  152-(52+31)\u00f7332  152-112\u00d7223=152-13  45 - 26=436=7.16\u22487","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>4","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Simplify the expression log1018 - log102.88 + log1016.","images":[],"options":{"A":"31.12","B":"3.112","C":"2","D":"1"},"answer":"C","explanation":"log1018 - log102.88 + log1016  log1018 + log1016 - log102.88  log10(18 \u00d7 162.88)=log10(2882.88)  log10100 = log10102 = 2log1010  \u21d2 2 \u00d7 1 = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>5","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Find the equation whose roots are 2 and -3 1/2.","images":[],"options":{"A":"2x2 + 3x + 14 = 0","B":"2x2 + 5x + 7 = 0","C":"2x2 + 5x - 7 = 0","D":"2x3 + 3x - 14 = 0"},"answer":"D","explanation":"(x-2)(x+72)  x2+72x-2x-7=0  multply through by 2  2x2 + 7x - 4x - 14 = 0  2x3 + 3x - 14 = 0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>6","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A man bought 220 mangoes at \u20a65x. He sold each for 3x kobo and made again of \u20a68. Find the value of x.","images":[],"options":{"A":"2","B":"5","C":"6","D":"10"},"answer":"B","explanation":"Selling Price - Cost price = Profit (gain)  Cost Price = \u20a65x  SellingPrice=\u20a6220 \u00d7 3x100=\u20a66.6x  Profit (gain) = \u20a66.6x - \u20a65x  8 = 6.6x - 5x = 1.6x  x=81.6=5","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>7","subject":"Mathematics","year":"2005","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"From a point P, R is 5km due west and 12km due south.  Find the distance between P and R.","images":[],"options":{"A":"5km","B":"12km","C":"13km","D":"17km"},"answer":"C","explanation":"Using pythagoras theorem  y2 = 52 + 122  y2 = 25 + 144  y2 = 169   y = &radic;169&nbsp;  y = 13km  Distance PR = 13km.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>8","subject":"Mathematics","year":"2005","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A fair die is tossed once, what is the probability of obtaining neither 5 nor 2?","images":[],"options":{"A":"56","B":"23","C":"12","D":"16"},"answer":"B","explanation":"S = {1, 2, 3, 4, 5, 6}  Pr (5 nor 2) = 1 - Pr(5) + Pr(2)  =1-16+16  =1-16=23","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>9","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, KL||MN,","images":["data:image/png;base64,"],"options":{"A":"285\u00b0","B":"255\u00b0","C":"225\u00b0","D":"210\u00b0"},"answer":"A","explanation":"30 + a = 180 (sum of the interior angle)  a = 180 - 30 = 150  45 + b = 180 (sum of the interior angle)  b = 180 - 45  b = 135  Reflex  \u21d2 150 + 135  \u21d2 285\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>10","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PR is a diameter,","images":["data:image/png;base64,"],"options":{"A":"x=75 - 2y3","B":"x=105 - 3y2","C":"x=105 - 2y3","D":"x=75 - 3y2"},"answer":"C","explanation":"RP\u0302Q + PR\u0302Q = 90\u00b0  2y - 7 + 3x - 8 = 90\u00b0  2y + 3x - 7 - 8 = 90\u00b0  2y + 3x = 90 + 15  3x3=105 - 2y3  x=105 - 2y3","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>11","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Convert 101101two to a number in base ten.","images":[],"options":{"A":"61","B":"46","C":"45","D":"44"},"answer":"C","explanation":"Convert 1011012 to base ten  1 x 25 + 0 x 24 + 1 x 23 + 1 x 22 + 0 \u00d7 21 + 1 \u00d7 20  32 + 0 + 8 + 4 + 0 + 1 = 4510","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>12","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Solve the equation 27 = 85 - x.","images":[],"options":{"A":"5/8","B":"8/3","C":"3/2","D":"15/4"},"answer":"B","explanation":"27 = 85 - x  27 = 23(5 - x)  27 = 215 - 3x  7 = 15 - 3x  7 - 15 = 3x  -8-3=-3x-3  x=83or223","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>13","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Expand (2x - 3y)(x - 5y)","images":[],"options":{"A":"2x2 + 13xy - 15y2","B":"2x2 - 13xy - 15y2","C":"2x2 + 13xy + 15y2","D":"2x2 - 13xy + 15y2"},"answer":"D","explanation":"(2x - 3y)(x - 5y)   By open the bracket   2x2 - 10xy - 3xy + 15y2  2x2 - 13xy + 15y2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>14","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Make f the subject of the relation v = u + ft","images":[],"options":{"A":"v - ut","B":"u - vt","C":"t(v + u)","D":"vu-t"},"answer":"A","explanation":"v = u + ft  ftt=v - ut  f=v - ut","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>15","subject":"Mathematics","year":"2005","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"The probabilities that John and James pass an examination are 3/4 and 3/5 respectively. Find the probability of both boys failing the examination.","images":[],"options":{"A":"1/10","B":"3/10","C":"9/20","D":"11/20"},"answer":"A","explanation":"Pr(Johnpass)=34  Pr(Johnfailed)=1-34=14  Pr(Jamespass)=35  Pr(Jamesfailed)=1-35=25  \u2234Pr(Bothfailed)=14\u00d725=110","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>16","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PQ and MN are straight lines. Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"13\u00b0","B":"17\u00b0","C":"28\u00b0","D":"30\u00b0"},"answer":"B","explanation":"2(x + 30)\u00b0 + 86\u00b0 = 180 (straight line)  2x + 60 + 86 = 180  2x + 146 = 180  2x = 180 - 146  2x2=342  x = 17\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>17","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PQRS is a parallelogram and","images":["data:image/png;base64,"],"options":{"A":"95\u00b0","B":"100\u00b0","C":"120\u00b0","D":"150\u00b0"},"answer":"D","explanation":"x = 150\u00b0 (opposite angles of a parallelogram are equal)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>18","subject":"Mathematics","year":"2005","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"From a point R, 300m north of P, a man walks eastwards to a place Q which is 600m from P. Find the bearing of P from Q correct to the nearest degree.","images":[],"options":{"A":"026\u00b0","B":"045\u00b0","C":"210\u00b0","D":"240\u00b0"},"answer":"D","explanation":"Usingsin\u03b8=opphyp  sin\u03b8=300600=0.5  \u03b8 = sin-1(0.5)  \u03b8 = 30\u00b0  \u03b8 + a = 90  30 + a = 90  a = 90 - 30  a = 60\u00b0  \u2234 90 + 90 + a  90 + 90 + 60 \u21d2 240\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>19","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The lengths of the adjacent sides of a right-angled triangle are x cm, (x - 1)cm. If the length of the hypotenuse is &radic;13&nbsp;cm, find the value of x.","images":[],"options":{"A":"2","B":"3","C":"4","D":"5"},"answer":"B","explanation":"x2 + (x - 1)2 = 13  ;   2x2 - 2x + 1 = 13  2x2 - 2x = 12  ;    2(x2 - x) = 12  x2 - x = 6   \u2234 x2 - x - 6 = 0  (x + 2)(x - 3) = 0   x = -2 or 3  x = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>20","subject":"Mathematics","year":"2005","type":"Objective","topic":"MENSURATION : AREAS","question":"What is the diameter of a circle of area 77cm2? (Take \u03c0 = 22/7)","images":[],"options":{"A":"&radic;2&nbsp;7cm","B":"312cm","C":"7 cm","D":"7&radic;2&nbsp;cm"},"answer":"D","explanation":"Diameter(D)2=r  \u2234r=D2  Area of a circle = \u03c0r2  77=\u03c0(D2)2  771=227\u00d7D24  77 \u00d7 28 = 22D2  215622=22D222  D2 = 98  D = &radic;98&nbsp;  D = &radic;49 \u00d7 2&nbsp; = 7&radic;2&nbsp;","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>21","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"Solve for y in the equations:  2x - 3y = 22  3x + 2y = 7","images":[],"options":{"A":"-5","B":"-4","C":"4","D":"5"},"answer":"B","explanation":"2x - 3y = 22 .................. (i) \u00d7 3  3x + 2y = 7 ................... (ii) \u00d7 2  6x - 9y = 66 ................... (iii)  6x + 4y = 14 .................. (iv)  -----------------------  -13y13=5213  -y = 4  y = -4.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>22","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Solve the equation   2y - 13-3y - 14=1","images":[],"options":{"A":"-8","B":"-13","C":"13","D":"19"},"answer":"B","explanation":"2y - 13-3y - 14=1  12(2y - 13)-12(3y - 14)=12\u00d71  4(2y - 1) - 3(3y - 1) = 12  8y - 9y - 4 + 3 = 12  -y - 1 = 12  -y = 12 + 1  -y = 13  y = -13","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>23","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle,","images":["data:image/png;base64,"],"options":{"A":"40\u00b0","B":"50\u00b0","C":"55\u00b0","D":"75\u00b0"},"answer":"C","explanation":"Assume  MOL = 140\u00b0 and NOL = 140\u00b0  15 + 140 + a = 180 (sum of  a = 180 - 155  a = 25  Also, 10 + 140 + b = 180 ( 150 + b = 180  b = 180 - 150  b = 30\u00b0  \u2234 x = a + b  x = 25 + 30  x = 55\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>24","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"If log9x = 1.5, find x","images":[],"options":{"A":"36","B":"27","C":"24.5","D":"13.5"},"answer":"B","explanation":"Log9x = 1.5  91.5 = x  x = 91.5/10  x = 91 1/2 = 93/2  x = (&radic;9&nbsp;)3  x = (3)3  x = 27","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>25","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"A sequence is given by 2 1/2, 5, 7 1/2, . . . If the nth term is 25, find n","images":[],"options":{"A":"9","B":"10","C":"12","D":"15"},"answer":"B","explanation":"L = a + (n - 1)d,  d = T2 - T1  d=51-52  d=10 - 52=52    25=212+(n-1)\u00d752  25=52+(5n2-52)  251=5 + 5n - 52  505=5n5  n = 10","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>26","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Given that one of the roots of the equation 2x2 + (k + 2)x + k = 0 is 2, find the value of k.","images":[],"options":{"A":"-4","B":"-2","C":"-1","D":"-1/4"},"answer":"A","explanation":"2x2 + (k + 2)x + k = 0   Let x = 2  2(2)2 + (k + 2)2 + k = 0  2(4) + 2k + 4 + k = 0  8 + 4 + 2k + k = 0  12 + 3k = 0  3k3=-123  k = -4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>27","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"The figure shows a quadrilateral PQRS having equal sides and opposite sides parallel. The diagonals PR and QS intersect perpendicularly at O, which of the following statements cannot be correct?","images":["data:image/png;base64,"],"options":{"A":"|PO| = |RO|","B":"PQR is an equilateral triangle","C":"PQRS is a parallelogram","D":"There are two lines of symmetry"},"answer":"B","explanation":"PQR is an equilateral triangle This is because an equilateral triangle has three equal sides.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>28","subject":"Mathematics","year":"2005","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the mean of the numbers 1, 3, 4, 8, 8, 4 and 7.","images":[],"options":{"A":"4","B":"5","C":"6","D":"7"},"answer":"B","explanation":"x\u0305=1 + 3 + 4 + 8 + 8 + 4 + 77=357=5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>29","subject":"Mathematics","year":"2005","type":"Objective","topic":"MENSURATION : AREAS","question":"What is the total surface area of a closed cylinder of height 10cm and diameter 7cm?","images":[],"options":{"A":"77cm2","B":"227cm2","C":"297cm2","D":"374cm2"},"answer":"C","explanation":"Total surface area of close cylinder = 2\u03c0r(h + r), r = 7/2  2x227x3.5(10+3.5)  2 x 22 x 3.5 x 13.57=2077 = 297cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>30","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"An arc of a circle of radius 14cm subtends angle 300\u00b0 at the centre. Find the perimeter of the sector formed by the arc. (Take \u03c0 = 22/7 )","images":[],"options":{"A":"14.67cm","B":"42.67cm","C":"101.33cm","D":"513.33cm"},"answer":"C","explanation":"Perimeter=2r+\u03b8360\u00d72\u03c0r  =(2\u00d714)+300360\u00d72\u00d7227\u00d714  =28+1848002520  \u21d2 28 + 73.33 = 101.33cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>31","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The figure is the graph of a quadratic equation. Use the information to answer this question      What are the roots of the equation?","images":["data:image/png;base64,"],"options":{"A":"-1 and 1","B":"4 and -1","C":"1 and 4","D":"4 and 4"},"answer":"C","explanation":"the roots of the equation are 1 and 4.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>32","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The figure is the graph of a quadratic equation. Use the information to answer this question    What is the equation of the curve?","images":["data:image/png;base64,"],"options":{"A":"y = x2 + 6x + 4","B":"y = x2 - 5x - 4","C":"y = x2 - 5x + 4","D":"y = x2 + 5x - 4"},"answer":"C","explanation":"From the graph roots are x = 1, x = 4  (x - 1)(x - 4)  x2 - 4x - x + 4 = 0  y = x2 - 5x + 4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>33","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : LOCI","question":"Which of the following statements describes the locus of a point R which moves in a plane such that it is equidistant from two intersecting lines?","images":[],"options":{"A":"The bisector of the angles formed by the lines","B":"The point of intersection of the two lines","C":"A cone, with the two intersecting lines as slant heights","D":"A circle, with the point of intersection of the two lines as the centre"},"answer":"A","explanation":"The bisector of the angles formed by the lines: This is the correct answer. If a point R moves in a plane such that it is equidistant from two intersecting lines, it will trace out the bisector of the angles formed by the lines. This is because the bisector is the line that divides an angle into two congruent angles, and any point on the bisector will be equidistant from the two sides of the angle.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>34","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"P = {3, 9, 11, 13} and Q = {3, 7, 9, 15} are subsets of the universal set \u03b5 = {{1, 3, 7, 9, 11, 13, 15}. Find P' \u2229 Q'.","images":[],"options":{"A":"{3, 9}","B":"{5, 7, 15}","C":"{1}","D":"{1, 11}"},"answer":"C","explanation":"\u03bc = {1, 3, 7, 9, 11, 13, 15}  P = {3, 9, 11, 13}  Q = {3, 7, 9, 15}  \u2234 P' = {1, 7, 15}  Q' = {1, 11, 13}  P' \u2229 Q' = {1}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>35","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"A train moving at a uniform speed, covers 36km in 21 minutes. How long does it take to cover 60km?","images":[],"options":{"A":"35 minutes","B":"40 minutes","C":"45 minutes","D":"90 minutes"},"answer":"A","explanation":"Time=DistanceSpeed  Time=3621=1.71min  Speed=distancetime  =601.7=35minutes","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>36","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"The salary of a man was increased in the ratio 40:47.  Calculate the percentage increase in the salary.","images":[],"options":{"A":"85.1%","B":"58.5%","C":"17.5%","D":"14.9%"},"answer":"C","explanation":"Percentageincrease=Salary - IncreasementSalary \u00d7 100  Salary: Increasement = 40 : 47  Salary = 40  Increasement = 47  \u223447 - 4040\u00d7100=17.5%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>37","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"A regular polygon has 9 sides. What is the size of one of its exterior angles?","images":[],"options":{"A":"20\u00b0","B":"40\u00b0","C":"90\u00b0","D":"140\u00b0"},"answer":"B","explanation":"Exterioranglesofpolygon=360\u00b0n  =3609=40","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>38","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:   23xy-34yz","images":[],"options":{"A":"2 - x12xyz","B":"2z - 3x12xyz","C":"4z - 3x12xyz","D":"8z - 9x12xyz"},"answer":"D","explanation":"23xy-34yz  12xyz \u00d7 2/3xy - 12xyz \u00d7 3/4yz 12xyz  4 \u00d7 2 \u00d7 z - 3 \u00d7 x \u00d7 32xyz  8z - 9x12xyz","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>39","subject":"Mathematics","year":"2005","type":"Objective","topic":"MENSURATION : AREAS","question":"The total surface area of the walls of a room, 7m long, 5m wide and x m high is 96m2. Find the value of x.","images":[],"options":{"A":"2/3","B":"2","C":"4","D":"8"},"answer":"C","explanation":"Total surface area = 2(wide \u00d7 x) + 2(length \u00d7 x)  where x is the height  Surface area = 96  96 = 10x + 14x  9624=24x24  x = 4","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>40","subject":"Mathematics","year":"2005","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the pocket money received by students in a class in a week. Use the bar chart to answer this question.    Find the total number of students in the class.","images":["data:image/png;base64,"],"options":{"A":"27","B":"31","C":"33","D":"34"},"answer":"D","explanation":"The total number of students in the class = 4 + 7 + 6 + 2 + 3 + 11 + 1 = 34","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>41","subject":"Mathematics","year":"2005","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the pocket money received by students in a class in a week. Use the bar chart to answer this question.  How many students received \u20a6300 or \u20a6500 for a week?","images":["data:image/png;base64,"],"options":{"A":"7","B":"11","C":"18","D":"19"},"answer":"C","explanation":"Number of students who received \u20a6300 or \u20a6500 for a week:  300 \u2192 7  500 \u2192 11  \u2234 7 + 11 = 18","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>42","subject":"Mathematics","year":"2005","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram PQRS is a circle, |PT| = |QT| and  What is the size of","images":["data:image/png;base64,"],"options":{"A":"40\u00b0","B":"70\u00b0","C":"80\u00b0","D":"140\u00b0"},"answer":"B","explanation":"QPR = QSR [ Also PQS = PRS (  70\u00b0 = d    Also PQS(a) = PRS  70 = d  d = 70\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>43","subject":"Mathematics","year":"2005","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The angle of elevation of the top of a cliff 15 meters high from a landmark is 60\u00b0. How far is the landmark from the foot of the cliff?  Leave your answer in surd form.","images":[],"options":{"A":"15&radic;3&nbsp;m","B":"15&radic;2&nbsp;m","C":"10&radic;3&nbsp;","D":"5&radic;3&nbsp;m"},"answer":"D","explanation":"Using   tan\u03b8=oppadj  tan60=15x  xtan60tan60=15tan60  x=15&radic;3&nbsp;  By rationalising   15&radic;3&nbsp;\u00d7&radic;3&nbsp;&radic;3&nbsp;  =15&radic;3&nbsp;3=5&radic;3&nbsp;m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>44","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"For what values of y is the expression  6y - 1y2 - y - 6 not defined?","images":[],"options":{"A":"1/6, 1/4","B":"3, -2","C":"-3, 2","D":"0, 1"},"answer":"B","explanation":"y2 - y - 6 = 0 not defined  (y2 - 3y) + (2y - 6) = 0  y(y - 3) + 2(y - 3) = 0  (y - 3)(y + 2) = 0  y = 3 or -2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>45","subject":"Mathematics","year":"2005","type":"Objective","topic":"MENSURATION : AREAS","question":"XOY is a sector of a circle centre O of radius 3.5cm which subtends an angle of 144\u00b0 at the centre. Calculate, in terms of \u03c0, the area of the sector.","images":[],"options":{"A":"1.4\u03c0 cm2","B":"2.8\u03c0cm2","C":"4.9\u03c0cm2","D":"9.8\u03c0cm2"},"answer":"C","explanation":"3.5=3510    Area=\u03b8360\u00d7\u03c0r2  =144360\u00d772\u00d772\u00d7\u03c0  =7056\u03c01440=49\u03c010=4.9\u03c0cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>46","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Represent the solution of 3x + 15 > 0 on a number line.","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"3x + 15 > 0  3x3>-153  x > -5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2005>47","subject":"Mathematics","year":"2005","type":"Objective","topic":"MENSURATION : VOLUMES","question":"A rectangular packet has inner dimension 16cm by 12cm by 6cm. How many cubes of sugar of side 2cm can be nearly packed into the packed?","images":[],"options":{"A":"90","B":"144","C":"150","D":"288"},"answer":"B","explanation":"Inner dimension of packet = 16 \u00d7 12 \u00d7 6 = 1152  dimension of cubes = 2 \u00d7 2 \u00d7 2 = 8  \u2234Numberofcubespackedinthepacket=11528 = 144","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>48","subject":"Mathematics","year":"2005","type":"Objective","topic":"ALGEBRAIC PROCESSES : FUNCTIONS AND RELATIONS","question":"If y \u03b1 1/x2 and y = 1 1/4 when x = 4, find the value of when x = 1/2","images":[],"options":{"A":"2 1/2","B":"5","C":"10","D":"80"},"answer":"D","explanation":"y=1x2  when y = 1 1/4 and x = 4  y=kx2  54=k42  54=k16  5 \u00d7 16 = 4k  804=4k4  k = 20  find y = ? when x = 1/2  y=kx2  y=20(1/2)2  y=20\u00f714  =20\u00d741 = 80  y = 80","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2005>49","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"Ladi sold a car for \u20a684,000 at a loss of 4%. How much did Ladi buy the car?","images":[],"options":{"A":"\u20a680,500","B":"\u20a680,640","C":"\u20a687,360","D":"\u20a687,500"},"answer":"D","explanation":"S.p - 84000  loss - 4%  c.p - x  \u2234 100 - 4 = 96%  96% amount to 84000  \u2234100%amountto=84000 \u00d7 10096 = \u20a687,500","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2005>50","subject":"Mathematics","year":"2005","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"The monthly salary of a man increases from \u20a62,700 to \u20a63,200. Find the percentage increase.","images":[],"options":{"A":"10%","B":"15%","C":"15.6%","D":"18.5%"},"answer":"D","explanation":"Increase in salary = 3200 - 2700  \u21d2 500  Percentageincrease=IncreaseInitial salary\u00d7100%  =5002700\u00d7100 = 18.5%","marks":"1","difficulty":"2"}];